def _parse_houdini_env(path):
    env = {}
    if not path or not os.path.isfile(path):
        return env
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            if '=' in line:
                key, val = line.split('=', 1)
                env[key.strip()] = val.strip()
    return env

def _parse_bat_env(path):
    env = {}
    if not path or not os.path.isfile(path):
        return env
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            lower = line.lower()
            if lower.startswith('set ') and '=' in line:
                rest = line[4:]
                key, val = rest.split('=', 1)
                env[key.strip()] = val.strip()
    return env

def _build_env(bat_file, houdini_env_file):
    env = os.environ.copy()
    houdini_vars = _parse_houdini_env(houdini_env_file)
    bat_vars = _parse_bat_env(bat_file)
    for k, v in houdini_vars.items():
        for ek, ev in env.items():
            v = v.replace(f'%{ek}%', ev)
        env[k] = v
    for k, v in bat_vars.items():
        for ek, ev in env.items():
            v = v.replace(f'%{ek}%', ev)
        env[k] = v
    return env

async def on_parameter_changed(self, name, value):
    if name == 'houdini_version' and value in VERSION_PATHS:
        self.set_parameter('hython.exe', VERSION_PATHS[value])

def _fail(self, msg):
    return {'success': False, 'stdout': '', 'stderr': msg, 'exit_code': -1, 'executed_actions': [], 'skipped_actions': []}

async def _set_outputs(self, result):
    for k, v in result.items():
        await self.set_output(k, v)
    await self.set_output('exec_out', True)

