        return result

    payload = {'hip_file': hip_file, 'actions': planned}
    payload_file = tempfile.NamedTemporaryFile(mode='w', suffix='.json', delete=False)
    script_file = tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False)
    results_file = tempfile.NamedTemporaryFile(mode='w', suffix='_results.json', delete=False)
    results_file.close()
    try:
        json.dump(payload, payload_file)
        payload_file.close()
        script_file.write(HOUDINI_RUNNER_SCRIPT)
        script_file.close()

        cmd = [hython, script_file.name, payload_file.name, results_file.name]
        self.log_info(f'Running Houdini {version}: {" ".join(cmd)}')

        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=600, env=env)

        executed = []
        houdini_errors = []
        try:
