                        merged['info'] = ar['info']
                    executed.append(merged)
                else:
                    houdini_errors.append(f'Action {ar["index"]} ({ar["type"]}): {ar["error"]}')
            houdini_errors.extend(hou_results.get('errors', []))
        except Exception:
